#include<bits/stdc++.h>
using namespace std;
int n,f[200010],g[200010],a[200010],s;
int calc()
{
    memset(f,0x8f,sizeof(f));
    memset(g,0x8f,sizeof(g));
    int ans=INT_MIN;
    for(int i=1;i<=n;i++)
    {
        f[i]=max(0,f[i-1])+a[i];
    }
    for(int i=n;i>=1;i--)
    {
        g[i]=max(0,g[i+1])+a[i];
    }
    for(int i=1;i<=n;i++)
    {
        f[i]=max(f[i-1],f[i]);
    }
    for(int i=n;i>=1;i--)
    {
        g[i]=max(g[i+1],g[i]);
    }
    for(int i=1;i<n;i++)
    {
        ans=max(ans,f[i]+g[i+1]);
    }
    return ans;
};
int main()
{
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
    }
    int ans1=calc(),ans2=INT_MIN;
    for(int i=1;i<=n;i++)
    {
        s+=a[i];
        a[i]=-a[i];
    }
    int tmp=calc();
    if(s+tmp!=0)
    {
        ans2=s+tmp;
    }
    printf("%d",max(ans1,ans2));
    return 0;
}
